#include "ezmk/cli.hpp"
#include "ezmk/config.hpp"
#include "ezmk/project.hpp"
#include "ezmk/build.hpp"
#include "ezmk/cache.hpp"
#include "ezmk/pkg.hpp"
#include "ezmk/repo.hpp"
#include "ezmk/util.hpp"
#include "ezmk/i18n.hpp"
#include "ezmk/lua_api.hpp"
#include "ezmk/file_watcher.hpp"
#include "ezmk/version.hpp"   // generated by build.sh
#include "ezmk/logo.gen.h"     // 0.9.6+: generated by embed_logo.py

#include <atomic>
#include <csignal>
#include <exception>
#include <iostream>
#include <thread>

// 0.2.5+: Auto-update repos helper — shared by build/run/watch commands.
static void auto_update_repos(const ezmk::cli::BuildOptions& opts) {
    if (opts.auto_update) {
        ezmk::util::info(ezmk::i18n::I18nKey::auto_updating_repos);
        ezmk::repo::update("", {ezmk::cli::Scope::Project,
                                 ezmk::cli::Scope::User,
                                 ezmk::cli::Scope::Global});
    }
}

int main(int argc, char** argv) {
    ezmk::util::init_console();
    ezmk::i18n::init();  // detect language, load locale data
    ezmk::lua::init();   // initialize Lua interpreter

    try {
        auto args = ezmk::cli::parse(argc, argv);

        switch (args.cmd) {

        case ezmk::cli::Command::Help: {
            // 0.9.6+: Show ASCII logo (with color when available)
            if (ezmk::EZMK_LOGO[0] != '\0') {
                bool use_color = ezmk::util::supports_color();
                if (use_color) {
                    std::cout << "\033[36m" << ezmk::EZMK_LOGO << "\033[0m\n";
                } else {
                    std::cout << ezmk::EZMK_LOGO << "\n";
                }
                // Show version below logo
                std::cout << ezmk::i18n::fmt(ezmk::i18n::I18nKey::version_output,
                                             {{"version", EZMK_VERSION}}) << "\n\n";
            }
            ezmk::cli::print_usage();
            break;
        }

        case ezmk::cli::Command::ProjectNew:
            ezmk::project::create_project(*args.project_name, args.project_type,
                                          args.disable_git_init, args.disable_gitignore);
            break;

        case ezmk::cli::Command::Version:
            std::cout << ezmk::i18n::fmt(ezmk::i18n::I18nKey::version_output,
                                         {{"version", EZMK_VERSION}}) << std::endl;
            break;

        case ezmk::cli::Command::ProjectBuild: {
            auto_update_repos(args.build_opts);
            auto cfg = ezmk::config::parse_config("ezmk.toml");
            ezmk::build::build_project(cfg, args.build_opts);
            break;
        }

        case ezmk::cli::Command::ProjectRun: {
            auto_update_repos(args.build_opts);
            auto cfg = ezmk::config::parse_config("ezmk.toml");
            auto exe = ezmk::build::build_project(cfg, args.build_opts);
            ezmk::util::info(ezmk::i18n::I18nKey::running,
                             {{"exe", exe.filename().string()}});
            // 0.2.5+: forward positional args (after "--") to the program.
            std::string cmd = "\"" + exe.string() + "\"";
            for (const auto& a : args.program_args) {
                cmd += " \"" + ezmk::util::escape_shell_arg(a) + "\"";
            }
            auto res = ezmk::util::run_command(cmd);
            if (!res.out.empty()) std::cout << res.out;
            if (!res.err.empty()) std::cerr << res.err;
            if (res.exit_code != 0) {
                return res.exit_code;
            }
            break;
        }

        case ezmk::cli::Command::ProjectClean:
            ezmk::cache::clear_cache();
            ezmk::util::remove_all(".ezmk/temp");
            ezmk::util::info(ezmk::i18n::I18nKey::cleaned);
            break;

        case ezmk::cli::Command::ProjectWatch: {
            // 0.2.3+: Watch mode — file monitoring + auto rebuild
            auto_update_repos(args.build_opts);
            auto cfg = ezmk::config::parse_config("ezmk.toml");
            auto proj_root = std::filesystem::current_path();

            // Build effective config (profile merge)
            ezmk::config::CompileSection compile_cfg = cfg.compile;
            ezmk::config::LinkSection link_cfg = cfg.link;
            if (!args.build_opts.profile.empty()) {
                auto it = cfg.compile_profiles.find(args.build_opts.profile);
                if (it != cfg.compile_profiles.end()) {
                    compile_cfg = ezmk::build::merge_compile_profile(compile_cfg, it->second);
                }
                auto lit = cfg.link_profiles.find(args.build_opts.profile);
                if (lit != cfg.link_profiles.end()) {
                    link_cfg = ezmk::build::merge_link_profile(link_cfg, lit->second);
                }
            }

            // SIGINT handler for graceful exit
            static std::atomic<bool> sigint_received{false};
            auto prev_handler = std::signal(SIGINT, [](int) {
                sigint_received = true;
            });

            // Initial build (unless --no-build-on-start)
            if (!args.watch_no_build_on_start) {
                try {
                    ezmk::build::build_project(cfg, args.build_opts);
                    ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                } catch (const std::exception& e) {
                    ezmk::util::error(std::string("initial build failed: ") + e.what());
                    ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                }
            } else {
                ezmk::util::info(ezmk::i18n::I18nKey::watch_skip_initial);
            }

            // Collect directories to watch
            std::vector<std::string> watch_dirs;
            watch_dirs.push_back("ezmk.toml"); // special: watch the config file itself
            for (auto& d : compile_cfg.src_dirs) {
                std::filesystem::path dir = d;
                if (dir.is_relative()) dir = proj_root / dir;
                if (std::filesystem::exists(dir)) watch_dirs.push_back(dir.string());
            }
            for (auto& d : compile_cfg.include_dirs) {
                std::filesystem::path dir = d;
                if (dir.is_relative()) dir = proj_root / dir;
                if (std::filesystem::exists(dir)) watch_dirs.push_back(dir.string());
            }

            // Create file watcher
            auto ezmk_toml_abs = std::filesystem::absolute(proj_root / "ezmk.toml").string();
            ezmk::util::FileWatcher watcher(
                [&](const std::filesystem::path& changed) {
                    auto changed_abs = std::filesystem::absolute(changed).string();
                    auto changed_name = changed.filename().string();

                    // Check if ezmk.toml changed → re-parse config, clear cache, full rebuild
                    if (changed_abs == ezmk_toml_abs || changed_name == "ezmk.toml") {
                        ezmk::util::info(ezmk::i18n::I18nKey::watch_config_changed);
                        ezmk::cache::clear_cache();
                        try {
                            auto new_cfg = ezmk::config::parse_config("ezmk.toml");
                            ezmk::build::build_project(new_cfg, args.build_opts);
                            ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                        } catch (const std::exception& e) {
                            ezmk::util::error(std::string("build failed: ") + e.what());
                            ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                        }
                        return;
                    }

                    // Source/header change → incremental build
                    ezmk::util::info(ezmk::i18n::I18nKey::watch_detected_change,
                                     {{"path", changed_abs}});
                    try {
                        auto cur_cfg = ezmk::config::parse_config("ezmk.toml");
                        ezmk::build::build_project(cur_cfg, args.build_opts);
                        ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                    } catch (const std::exception& e) {
                        ezmk::util::error(std::string("build failed: ") + e.what());
                        ezmk::util::info(ezmk::i18n::I18nKey::watch_started);
                    }
                },
                300  // 300ms debounce
            );

            // Add directories to watcher
            for (auto& d : watch_dirs) {
                std::filesystem::path dp(d);
                if (dp.filename() == "ezmk.toml") {
                    // Watch the parent directory of ezmk.toml non-recursively
                    watcher.add_directory(dp.parent_path(), /*recursive=*/false);
                } else {
                    watcher.add_directory(dp, /*recursive=*/true);
                }
            }

            // Run watcher in background thread, main thread waits for SIGINT
            std::thread watcher_thread([&watcher]() {
                watcher.run();
            });

            // Wait for SIGINT
            while (!sigint_received) {
                std::this_thread::sleep_for(std::chrono::milliseconds(200));
            }

            ezmk::util::info(ezmk::i18n::I18nKey::watch_stopping);
            watcher.stop();
            if (watcher_thread.joinable()) watcher_thread.join();

            // Restore previous handler
            std::signal(SIGINT, prev_handler);
            break;
        }

        case ezmk::cli::Command::PkgInstall: {
            auto& opts = *args.install_opts;
            ezmk::pkg::install(opts.pkg_file, opts.scope, opts.sha256, opts.assume_yes);
            break;
        }

        case ezmk::cli::Command::PkgRemove: {
            auto& opts = *args.query_opts;
            ezmk::pkg::remove(opts.pkg_name, opts.scopes);
            break;
        }

        case ezmk::cli::Command::PkgSearch: {
            auto& opts = *args.query_opts;
            auto results = ezmk::pkg::search(opts.pkg_name, opts.scopes);
            if (results.empty()) {
                ezmk::util::info(ezmk::i18n::I18nKey::not_found,
                                 {{"pkg", opts.pkg_name}});
            } else {
                for (auto& p : results) {
                    std::cout << p.string() << "\n";
                }
            }
            break;
        }

        case ezmk::cli::Command::PkgInfo: {
            auto& opts = *args.query_opts;
            ezmk::pkg::info(opts.pkg_name, opts.scopes);
            break;
        }

        case ezmk::cli::Command::PkgList: {
            // 0.2.3+ — implementation in Phase 5
            auto& opts = *args.query_opts;
            ezmk::pkg::list(opts.scopes);
            break;
        }

        case ezmk::cli::Command::PkgUpdate: {
            auto& opts = *args.query_opts;
            if (opts.update_all) {
                ezmk::pkg::update_all(opts.scopes);
            } else {
                ezmk::pkg::update(opts.pkg_name, opts.scopes);
            }
            break;
        }

        case ezmk::cli::Command::RepoAdd:
            ezmk::repo::add(args.repo_opts);
            break;

        case ezmk::cli::Command::RepoRemove:
            ezmk::repo::remove(args.repo_opts.name, args.repo_opts.scopes);
            break;

        case ezmk::cli::Command::RepoUpdate:
            ezmk::repo::update(args.repo_opts.name, args.repo_opts.scopes);
            break;

        case ezmk::cli::Command::RepoList:
            ezmk::repo::list(args.repo_opts.scopes);
            break;

        case ezmk::cli::Command::RepoInfo:   // 0.2.5+
            ezmk::repo::info(args.repo_opts.name, args.repo_opts.scopes);
            break;

        case ezmk::cli::Command::Utils: {
            // Search for the Lua script across project/user/global scopes
            auto script_path = ezmk::util::find_utils_script(args.utils_name);
            if (script_path.empty()) {
                ezmk::util::fatal(ezmk::i18n::I18nKey::utils_not_found,
                                  {{"name", args.utils_name}});
            }
            int rc = ezmk::lua::run_script(ezmk::lua::state(), script_path,
                                           args.utils_args);
            if (rc != 0) return rc;
            break;
        }

        } // switch

    } catch (const ezmk::fatal_error&) {
        // fatal() already printed the message; just clean up
        ezmk::util::remove_all(".ezmk/temp");
        ezmk::lua::shutdown();
        return 1;
    } catch (const std::exception& e) {
        ezmk::util::error(e.what());
        ezmk::util::remove_all(".ezmk/temp");
        ezmk::lua::shutdown();
        return 1;
    }

    ezmk::lua::shutdown();
    return 0;
}
